#include <iostream>
#include <string>

using namespace std;

class Student
{
public:
    string name;
    int age;
    double marks;

    void display()
    {
        cout << name << ", age " << age << ", marks " << marks;
    }
};

int main()
{
    Student s1;
    s1.name = "Aman";
    s1.age = 20;
    s1.marks = 88.5;

    s1.display();

    return 0;
}

Student s1;
s1.name = "Aman";
s1.age = 20;

Student s2;
s2.name = "Priya";
s2.age = 22;

// s1 and s2 are completely separate — changing one never affects the other

